// ListEventType - A user-facing event type.
type ListEventType struct {
	// The name of the event type.
	Name ListEventTypeName `json:"name"`
	// Description of the event, visible to users in the Activity dashboard and docs.
	Description string `json:"description"`
	// Categories that group this event type with related event types.
	Categories []ListEventTypeCategory `json:"categories"`
	// Present only when this event type is deprecated.
	Deprecated *bool `json:"deprecated,omitempty"`
	// Event type names that supersede this deprecated event type.
	ReplacedBy []ReplacedBy `json:"replacedBy,omitempty"`
}

func (o *ListEventType) GetName() ListEventTypeName {
	if o == nil {
		return ListEventTypeName("")
	}
	return o.Name
}

func (o *ListEventType) GetDescription() string {
	if o == nil {
		return ""
	}
	return o.Description
}

func (o *ListEventType) GetCategories() []ListEventTypeCategory {
	if o == nil {
		return []ListEventTypeCategory{}
	}
	return o.Categories
}

func (o *ListEventType) GetDeprecated() *bool {
	if o == nil {
		return nil
	}
	return o.Deprecated
}

func (o *ListEventType) GetReplacedBy() []ReplacedBy {
	if o == nil {
		return nil
	}
	return o.ReplacedBy
}
